entries.source:
:local ident [/system identity get name]
:local date [/system clock get date]
:local time [/system clock get time]
:local stamp ($date . "-" . [:pick $time 0 2] . [:pick $time 3 5] . [:pick $time 6 8])
:local backupName ($ident . "-backup-" . $stamp)

:log info ("BackupAndUpdate: starting backup " . $backupName)

:do {
    /system backup save dont-encrypt=yes name=$backupName
    :log info ("BackupAndUpdate: system backup saved " . $backupName . ".backup")
} on-error={
    :log error "BackupAndUpdate: system backup failed"
    :error "BackupAndUpdate system backup failed"
}

:delay 2s

:do {
    /export compact hide-sensitive file=$backupName
    :log info ("BackupAndUpdate: config export saved " . $backupName . ".rsc")
} on-error={
    :log error "BackupAndUpdate: config export failed"
    :error "BackupAndUpdate config export failed"
}

:log info ("BackupAndUpdate: completed " . $backupName)

:log info "Testing Spectrum WAN latency"
:local count 0
:local sum 0
:local min 999999
:local max 0
:local loss 0

:for i from=1 to=50 do={
    :local result [/ping 1.1.1.1 count=1 interface=ether1-WAN-Spectrum as-value]
    :if (($result->"received") > 0) do={
        :local time ($result->"avg-rtt")
        :set sum ($sum + $time)
        :set count ($count + 1)
        :if ($time < $min) do={ :set min $time }
        :if ($time > $max) do={ :set max $time }
    } else={
        :set loss ($loss + 1)
    }
}

:if ($count > 0) do={
    :local avg ($sum / $count)
    :put ("Spectrum Results:")
    :put ("  Packets: sent=50 received=$count loss=$loss")
    :put ("  Latency: min=$min avg=$avg max=$max")
} else={
    :put "Spectrum: All packets lost"
}

