# Refresh blizzard-games address list for Diablo / Blizzard titles

:local targetList "blizzard-games"
:local old [/ip firewall address-list find list=$targetList]
:if ([:len $old] > 0) do={
    /ip firewall address-list remove $old
}

# Dynamic domains (single IPs, refreshed every run). Some hostnames may not resolve at every run.
:foreach d in={"us.actual.battle.net";"prod.actual.battle.net";"gameplay.blizzard.com";"instance-server.blizzard.com"} do={
    :do {
        :local resolved [:resolve $d]
        :if ([:len $resolved] > 0) do={
            :local existing [/ip firewall address-list find list=$targetList address=$resolved]
            :if ([:len $existing] = 0) do={
                /ip firewall address-list add list=$targetList address=$resolved timeout=12h comment=("dyn-" . $d)
            }
        }
    } on-error={}
}

# Static fallback subnets (Cloudflare + GCP hosting Blizzard infra)
:foreach net in={"162.159.128.0/19";"162.159.136.0/22";"162.159.192.0/19";"34.125.0.0/16";"34.133.0.0/16"} do={
    :do {
        :local existing [/ip firewall address-list find list=$targetList address=$net]
        :if ([:len $existing] = 0) do={
            /ip firewall address-list add list=$targetList address=$net timeout=30d comment="blizzard-range"
        }
    } on-error={}
}
:log info "blizzard-update: completed"

# Refresh steam-games address list for Steam / Valve game traffic

:local targetList "steam-games"
:local old [/ip firewall address-list find list=$targetList]
:if ([:len $old] > 0) do={
    /ip firewall address-list remove $old
}

# Dynamic Steam core domains. Some parent domains may not resolve directly at every run.
:foreach d in={"steamserver.net";"steamcontent.com";"steam-chat.com";"steamconnection.com"} do={
    :do {
        :local resolved [:resolve $d]
        :if ([:len $resolved] > 0) do={
            :local existing [/ip firewall address-list find list=$targetList address=$resolved]
            :if ([:len $existing] = 0) do={
                /ip firewall address-list add list=$targetList address=$resolved timeout=12h comment=("dyn-" . $d)
            }
        }
    } on-error={}
}

# Copy existing Valve Network ranges into steam-games for QoS
:foreach r in=[/ip firewall address-list find list="Valve Network"] do={
    :do {
        :local addr [/ip firewall address-list get $r address]
        :local existing [/ip firewall address-list find list=$targetList address=$addr]
        :if ([:len $existing] = 0) do={
            /ip firewall address-list add list=$targetList address=$addr timeout=30d comment="valve-range"
        }
    } on-error={}
}
:log info "steam-update: completed"

:foreach i in=[1,2,3] do={
    :if ($i = 2) do={
        :continue
    }
    :put ("i=" . $i)
}

:local gamerList   "GAMER-DEVICES"
:local learnList   "auto-games"
:local promoteList "auto-games-promoted"

:local learnTTL    "30m"
:local promoteTTL  "4w"

:local minPackets  400
:local minBytes    1000000

# Use print as-value snapshots instead of volatile item ids. Connection/address-list
# items can disappear between find and get, which causes intermittent "no such item".
# Guard snapshot acquisition too: RouterOS connection rows can churn during print as-value.
:local gamers
:local conns
:do {
    :set gamers [/ip firewall address-list print as-value where list=$gamerList]
    :set conns [/ip firewall connection print as-value where protocol=udp]
} on-error={
    :return
}

# Guard per-row connection parsing so one incomplete/churned row does not abort the run.

:foreach g in=$gamers do={
    :do {
        :local gamerIP [:tostr ($g->"address")]
        :if ([:len $gamerIP] > 0) do={
            :foreach c in=$conns do={
                :do {
                    :local srcFull [:tostr ($c->"src-address")]
                    :if ([:find $srcFull ($gamerIP . ":")] = 0) do={
                        :local dstFull [:tostr ($c->"dst-address")]
                        :local colonPos [:find $dstFull ":"]
                        :local dst $dstFull
                        :if ($colonPos != nil) do={
                            :set dst [:pick $dstFull 0 $colonPos]
                        }

                        :local dptText [:tostr ($c->"dst-port")]
                        :if ([:pick [:tostr $dst] 0 3] != "10.") do={
                            :if (([:len $dptText] > 0) && ([:find $dptText "-"] = nil)) do={
                                :local dptNum [:tonum $dptText]
                                :if ($dptNum >= 1024) do={
                                    :local p [:tonum [:tostr ($c->"orig-packets")]]
                                    :local b [:tonum [:tostr ($c->"orig-bytes")]]

                                    :if (($p >= $minPackets) && ($b >= $minBytes)) do={
                                        :do {
                                            :local existingLearn [/ip firewall address-list find list=$learnList address=$dst]
                                            :if ([:len $existingLearn] = 0) do={
                                                /ip firewall address-list add list=$learnList address=$dst timeout=$learnTTL comment="auto-game-detect"
                                            }
                                        } on-error={}

                                        :local udpHits 0
                                        :foreach c2 in=$conns do={
                                            :do {
                                                :local dst2Full [:tostr ($c2->"dst-address")]
                                                :local dst2Colon [:find $dst2Full ":"]
                                                :local dst2 $dst2Full
                                                :if ($dst2Colon != nil) do={
                                                    :set dst2 [:pick $dst2Full 0 $dst2Colon]
                                                }
                                                :if ($dst2 = $dst) do={
                                                    :set udpHits ($udpHits + 1)
                                                }
                                            } on-error={}
                                        }

                                        :if ($udpHits >= 2) do={
                                            :do {
                                                :local existingPromote [/ip firewall address-list find list=$promoteList address=$dst]
                                                :if ([:len $existingPromote] = 0) do={
                                                    /ip firewall address-list add list=$promoteList address=$dst timeout=$promoteTTL comment="promoted-game-server"
                                                }
                                            } on-error={}
                                        }
                                    }
                                }
                            }
                        }
                    }
                } on-error={}
            }
        }
    } on-error={}
}
